mapper.select:
SELECT integralInfo.id,integralInfo.integral_type,integralInfo.integral_num,integralInfo.integral_title, integralInfo.integral_badge FROM ( SELECT DISTINCT( integralInfo.id ),integralInfo.integral_type,integralInfo.integral_num, integralInfo.integral_title,integralInfo.integral_badge FROM t_integral_info integralInfo LEFT JOIN t_user_integral_info userIntegralInfo ON integralInfo.integral_type = userIntegralInfo.integral_type WHERE userIntegralInfo.integral_num <= integralInfo.integral_num
AND userIntegralInfo.user_id=#{userId}
ORDER BY integralInfo.integral_num ) integralInfo GROUP BY integralInfo.integral_type

SELECT ROW_NUMBER() OVER ( ORDER BY userInfo.integral_num DESC ) AS row_num,userInfo.user_name,userInfo.integral_num,userInfo.integral_title, (SELECT GROUP_CONCAT( dept.`name` ) FROM sys_dept dept WHERE FIND_IN_SET(dept.id,REPLACE ( REPLACE ( userInfo.department, '[', '' ), ']', '' ))) AS dept_name FROM (SELECT `user`.`name` as user_name,`user`.department,userIntegralInfo.integral_num,integralInfo.integral_title, integralInfo.integral_badge FROM t_user_integral_info userIntegralInfo LEFT JOIN sys_user `user` ON userIntegralInfo.user_id = `user`.user_id INNER JOIN t_integral_info integralInfo ON userIntegralInfo.integral_type = integralInfo.integral_type WHERE integralInfo.integral_num =( SELECT min( integralInfo1.integral_num ) integral_num FROM t_integral_info integralInfo1 WHERE userIntegralInfo.integral_num <= integralInfo1.integral_num
AND integralInfo.integral_type =#{integralType}
) ) userInfo

SELECT IntegralInfo.row_num,IntegralInfo.integral_num,IntegralInfo.integral_title,userInfo.`name`, userInfo.create_time,IF( ISNULL( shareInfo.share_num ), 0, shareInfo.share_num ) AS share_num FROM sys_user userInfo LEFT JOIN ( SELECT ROW_NUMBER() OVER ( ORDER BY IntegralInfo.integral_num DESC ) AS row_num,IntegralInfo.integral_num,IntegralInfo.integral_title,IntegralInfo.user_id FROM ( SELECT userIntegralInfo.integral_num,integralInfo.integral_title,integralInfo.integral_badge, userIntegralInfo.user_id FROM t_user_integral_info userIntegralInfo INNER JOIN t_integral_info integralInfo ON userIntegralInfo.integral_type = integralInfo.integral_type WHERE integralInfo.integral_num =( SELECT min( integralInfo1.integral_num ) integral_num FROM t_integral_info integralInfo1 WHERE integralInfo1.integral_type = "1" AND userIntegralInfo.integral_num <= integralInfo1.integral_num ) ) IntegralInfo ) IntegralInfo ON userInfo.user_id = IntegralInfo.user_id LEFT JOIN ( SELECT count(*) AS share_num,dataInfo.user_id FROM t_data_info dataInfo LEFT JOIN t_data_audit_record auditRecord ON dataInfo.data_id = auditRecord.data_id
AND auditRecord.audit_status = #{auditStatus}
GROUP BY dataInfo.user_id ) shareInfo ON userInfo.user_id = shareInfo.user_id
AND userInfo.user_id = #{userId}
